create schema if not exists plantaopro;
create extension if not exists pgcrypto;

create table if not exists plantaopro.cid_capitulos (id uuid primary key default gen_random_uuid(), versao text not null default 'CID-10', codigo text not null default '', nome text not null default '', descricao text not null default '', ordem int not null default 0, status text not null default 'ATIVO', reg_date timestamp without time zone not null default now(), reg_status char(1) not null default 'A');
create table if not exists plantaopro.cid_grupos (id uuid primary key default gen_random_uuid(), versao text not null default 'CID-10', capitulo_codigo text not null default '', codigo text not null default '', nome text not null default '', descricao text not null default '', status text not null default 'ATIVO', reg_date timestamp without time zone not null default now(), reg_status char(1) not null default 'A');
create table if not exists plantaopro.cid_tabela (id uuid primary key default gen_random_uuid(), versao text not null default 'CID-10', codigo text not null default '', descricao text not null default '', descricao_normalizada text not null default '', capitulo_codigo text not null default '', capitulo_nome text not null default '', grupo_codigo text not null default '', grupo_nome text not null default '', categoria text not null default '', fonte text not null default '', fonte_url text not null default '', data_importacao timestamp without time zone not null default now(), vigencia_inicio date null, vigencia_fim date null, status text not null default 'ATIVO', created_by uuid null, updated_by uuid null, created_at timestamp without time zone not null default now(), updated_at timestamp without time zone null, reg_date timestamp without time zone not null default now(), reg_update timestamp without time zone null, reg_status char(1) not null default 'A');
alter table plantaopro.cid_tabela add column if not exists versao text not null default 'CID-10';
alter table plantaopro.cid_tabela add column if not exists descricao_normalizada text not null default '';
alter table plantaopro.cid_tabela add column if not exists capitulo_codigo text not null default '';
alter table plantaopro.cid_tabela add column if not exists capitulo_nome text not null default '';
alter table plantaopro.cid_tabela add column if not exists grupo_codigo text not null default '';
alter table plantaopro.cid_tabela add column if not exists grupo_nome text not null default '';
alter table plantaopro.cid_tabela add column if not exists fonte text not null default '';
alter table plantaopro.cid_tabela add column if not exists fonte_url text not null default '';
alter table plantaopro.cid_tabela add column if not exists data_importacao timestamp without time zone not null default now();
update plantaopro.cid_tabela set descricao_normalizada = upper(coalesce(descricao,'')) where descricao_normalizada = '';
create table if not exists plantaopro.cid_favoritos (id uuid primary key default gen_random_uuid(), tenant_id uuid null, cliente_id uuid null, cid_id uuid null, medico_id uuid null, usuario_id uuid null, status text not null default 'ATIVO', created_by uuid null, updated_by uuid null, created_at timestamp without time zone not null default now(), updated_at timestamp without time zone null, reg_date timestamp without time zone not null default now(), reg_update timestamp without time zone null, reg_status char(1) not null default 'A');
create table if not exists plantaopro.cid_uso_historico (id uuid primary key default gen_random_uuid(), tenant_id uuid null, cliente_id uuid null, cid_id uuid null, consulta_id uuid null, paciente_id uuid null, medico_id uuid null, usuario_id uuid null, status text not null default 'REGISTRADO', created_by uuid null, created_at timestamp without time zone not null default now(), reg_date timestamp without time zone not null default now(), reg_status char(1) not null default 'A');
create table if not exists plantaopro.cid_importacoes (id uuid primary key default gen_random_uuid(), tenant_id uuid null, cliente_id uuid null, versao text not null default 'CID-10', fonte text not null default '', fonte_url text not null default '', arquivo_nome text not null default '', total_linhas int not null default 0, total_inseridos int not null default 0, total_atualizados int not null default 0, total_erros int not null default 0, status text not null default 'PROCESSADA', detalhes text not null default '', created_by uuid null, reg_date timestamp without time zone not null default now(), reg_status char(1) not null default 'A');
create table if not exists plantaopro.cid_fontes (id uuid primary key default gen_random_uuid(), versao text not null default 'CID-10', nome text not null default '', url text not null default '', oficial boolean not null default false, status text not null default 'ATIVO', reg_date timestamp without time zone not null default now(), reg_status char(1) not null default 'A');
create unique index if not exists ux_cid_tabela_versao_codigo_ativo on plantaopro.cid_tabela(versao, upper(codigo)) where reg_status='A' and codigo <> '';
create index if not exists ix_cid_tabela_codigo on plantaopro.cid_tabela(codigo); create index if not exists ix_cid_tabela_descricao on plantaopro.cid_tabela(descricao); create index if not exists ix_cid_tabela_descricao_normalizada on plantaopro.cid_tabela(descricao_normalizada); create index if not exists ix_cid_tabela_capitulo_codigo on plantaopro.cid_tabela(capitulo_codigo); create index if not exists ix_cid_tabela_grupo_codigo on plantaopro.cid_tabela(grupo_codigo); create index if not exists ix_cid_tabela_status on plantaopro.cid_tabela(status); create index if not exists ix_cid_tabela_versao on plantaopro.cid_tabela(versao);
create index if not exists ix_cid_capitulos_codigo on plantaopro.cid_capitulos(versao,codigo); create index if not exists ix_cid_grupos_codigo on plantaopro.cid_grupos(versao,codigo); create index if not exists ix_cid_importacoes_reg_date on plantaopro.cid_importacoes(reg_date);
